mapper.select:
SELECT ws.work_id AS workId, w.title AS workTitle, ROUND(AVG(ws.total), 2) AS avgTotal, ROUND(AVG(ws.innovation), 2) AS avgInnovation, ROUND(AVG(ws.difficulty), 2) AS avgDifficulty, ROUND(AVG(ws.completion), 2) AS avgCompletion, ROUND(AVG(ws.practicality), 2) AS avgPracticality, COUNT(ws.id) AS teacherCount FROM work_score ws INNER JOIN work w ON w.id = ws.work_id
ws.deleted = 0 AND w.deleted = 0 AND ws.batch_id = #{batchId} AND ws.work_id = #{workId}
GROUP BY ws.work_id
